  (0, 'Segnalazione visiva e illuminazione dei veicoli', 'NORME DI COMPORTAMENTO', NULL, NULL,
   NULL, 'Regolamenta la disciplina delle segnalazioni visive e di illuminazione dei veicoli', '152-1', NULL,
   'art. 152 comma 1 in relazione all''art. 152 comma 2', NULL, 'Circolava alla guida del ciclomotore o del motociclo, anche nei centri abitati, senza fare uso dei proiettori anabbaglianti.', NULL,
