  (0, 'Segnalazione di veicolo fermo', 'NORME DI COMPORTAMENTO', NULL, NULL,
   NULL, 'Regolamenta la segnalazione dei veicoli fermi Il regolamento specifica: il presegnalamento e la posizione del segnale mobile di pericolo; tipo ed omologazione del segnale mobile di pericolo; caratteristiche del segnale mobile di pericolo.', '162-1', NULL,
