   'art. 188-bis comma 1 in relazione all''art. 188-bis comma 3', NULL, 'Usufruiva della strutture di cui al comma 1: - senza avere l''autorizzazione prescritta dal comma 2; - facendone un uso improprio.', NULL,
   87, 60.9, NULL, NULL,
